tlDataChunk*
tlSkinChunk::LoadSubChunk(tlFile* f)
{
    tlDataChunk *dch;
    tlReadChunk16  ch(f);
    ch.ReadNext();
    unsigned int id = ch.GetID();
 
    switch(id)
    {
    case Pure3D::Mesh::PRIMGROUP:
        dch = new tlPrimGroupChunk(&ch);
        break;
    case Pure3D::Mesh::BOX:
        dch = new tlBBoxChunk(&ch);
        break;
    case Pure3D::Mesh::SPHERE:
        dch = new tlBSphereChunk(&ch);
        break;
    case Pure3D::Mesh::EXPRESSIONOFFSETS:
        dch = new tlExpressionOffsetsChunk(&ch);
        break;
    default:
        dch = new tlDataChunk(id);
        int size = ch.GetDataSize();
        char* buf = new char[size];
        f->GetBytes(buf, size);
        dch->SetData(buf, size);
        delete buf;
    }
    ch.Skip();
    return dch;
}

